  1→// SPDX-License-Identifier: MIT
  2→pragma solidity ^0.8.24;
  3→
  4→import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
  5→import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
  6→import {AccessControlUpgradeable} from "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
  7→import {PausableUpgradeable} from "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
  8→import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
  9→import {UUPSUpgradeable} from "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
 10→import {Initializable} from "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
 11→import {IClawQuestEscrow} from "./interfaces/IClawQuestEscrow.sol";
 12→
 13→/// @title ClawQuestEscrow
 14→/// @notice Singleton escrow contract for ClawQuest reward distribution.
 15→///         One instance per chain. Sponsors deposit funds for quests,
 16→///         operators distribute to winners, sponsors can emergency-withdraw
 17→///         if the backend goes offline.
 18→/// @dev UUPS upgradeable. Uses OpenZeppelin AccessControl for role management.
 19→contract ClawQuestEscrow is
 20→    Initializable,
 21→    AccessControlUpgradeable,
 22→    PausableUpgradeable,
 23→    ReentrancyGuard,
 24→    UUPSUpgradeable,
 25→    IClawQuestEscrow
 26→{
 27→    using SafeERC20 for IERC20;
 28→
 29→    // ──────────────────────────────────────────────
 30→    //  Roles
 31→    // ──────────────────────────────────────────────
 32→
 33→    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
 34→    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
 35→    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");
 36→
 37→    // ──────────────────────────────────────────────
 38→    //  State
 39→    // ──────────────────────────────────────────────
 40→
 41→    /// @notice Quest escrow data keyed by quest ID (UUID as bytes32)
 42→    mapping(bytes32 => QuestEscrow) private _quests;
 43→
 44→    /// @notice Token allowlist — only allowed tokens can be deposited
 45→    mapping(address => bool) private _allowedTokens;
 46→
 47→    /// @notice Grace period after quest expiry before sponsor can emergency-withdraw
 48→    uint64 public constant EMERGENCY_GRACE_PERIOD = 30 days;
 49→
 50→    // ──────────────────────────────────────────────
 51→    //  Initializer (replaces constructor for proxy)
 52→    // ──────────────────────────────────────────────
 53→
 54→    /// @custom:oz-upgrades-unsafe-allow constructor
 55→    constructor() {
 56→        _disableInitializers();
 57→    }
 58→
 59→    /// @notice Initialize the escrow contract
 60→    /// @param admin Address that receives DEFAULT_ADMIN_ROLE
 61→    /// @param operator Address that receives OPERATOR_ROLE (backend hot wallet)
 62→    function initialize(address admin, address operator) external initializer {
 63→        __AccessControl_init();
 64→        __Pausable_init();
 65→
 66→        _grantRole(DEFAULT_ADMIN_ROLE, admin);
 67→        _grantRole(OPERATOR_ROLE, operator);
 68→        _grantRole(PAUSER_ROLE, admin);
 69→        _grantRole(PAUSER_ROLE, operator);
 70→        _grantRole(UPGRADER_ROLE, admin);
 71→    }
 72→
 73→    // ──────────────────────────────────────────────
 74→    //  Sponsor Functions (permissionless)
 75→    // ──────────────────────────────────────────────
 76→
 77→    /// @inheritdoc IClawQuestEscrow
 78→    function deposit(
 79→        bytes32 questId,
 80→        address token,
 81→        uint128 amount,
 82→        uint64 expiresAt
 83→    ) external nonReentrant whenNotPaused {
 84→        if (amount == 0) revert ZeroAmount();
 85→        if (!_allowedTokens[token]) revert TokenNotAllowed(token);
