import { z } from 'zod';

// ─── Request schemas ────────────────────────────────────────────────────────

export const walletPortfolioQuerySchema = z.object({
    address: z.string().min(1, 'Wallet address required'),
    chainIds: z.string().optional().default('1,8453,56'), // Ethereum, Base, BSC
